export function getPage(slug) {
  return pages.find(p => p.slug === slug && p.product_type !== 'treasure-hunt')
}


export function getTreasurePage(slug) {
  return pages.find(p => p.slug === slug && p.product_type === 'treasure-hunt')
}

export function getAllSlugs() {
  return pages
    .filter(p => p.product_type !== 'treasure-hunt')
    .map(p => ({ params: { slug: p.slug }, props: { page: p } }))
}

export function getAllTreasureSlugs() {
  return pages
    .filter(p => p.product_type === 'treasure-hunt')
    .map(p => ({ params: { slug: p.slug }, props: { page: p } }))
}

